svg.script:
// ===========================================
// K'UHUL SVG-3D ↔ GGL NEURAL BRIDGE RUNTIME
// ===========================================

class NeuralKuhulBridge {
  constructor() {
    // Bridge state with neural components
    this.svg3dTokenizer = null;
    this.gglTokenizer = null;
    this.neuralModel = null;
    this.bridgeState = {
      translations: [],
      attentionWeights: [],
      tokenCache: new Map(),
      weightMatrices: new Map(),
      performance: {
        tokenizationTime: 0,
        inferenceTime: 0,
        attentionTime: 0
      }
    };

    // Initialize neural bridge
    this.initNeuralBridge();
  }

  async initNeuralBridge() {
    // Load embedded tokenizers
    this.svg3dTokenizer = await this.loadSVG3DTokenizer();
    this.gglTokenizer = await this.loadGGLTokenizer();

    // Initialize neural model (simplified for SVG)
    this.neuralModel = new NeuralBridgeModel();

    // Initialize visualization
    this.initWeightVisualization();
    this.initAttentionVisualization();

    // Update UI
    this.updateBridgeStatus('Neural Bridge Initialized');
    this.logNeural('Neural bridge ready with embedded weights & tokenizers');

    // Update model stats
    this.updateModelStats();
  }

  // ===========================================
  // EMBEDDED TOKENIZERS
  // ===========================================

  async loadSVG3DTokenizer() {
    // Simulate loading embedded SVG-3D tokenizer
    return {
      name: 'SVG-3D Tokenizer',
      vocabSize: 50257,
      specialTokens: {
        BOS: '⟨svg3d⟩',
        EOS: '⟨/svg3d⟩',
        PAD: '⟨pad⟩',
        SEP: '⟨sep⟩',
        MASK: '⟨mask⟩'
      },
      operators: {
        encrypt: '⤍',
        rotate: '↻', 
        sphere: '⟲',
        generate: '⟿',
        decrypt: '⤎',
        mirror: '↔',
        conditional: '⤦',
        weights: '⤂'
      },

      tokenize: function(text) {
        const tokens = [];
        const words = text.split(/\s+/);

        for (const word of words) {
          if (this.operators[word]) {
            tokens.push({ token: this.operators[word], type: 'operator' });
          } else if (word.match(/^[◯□△⍯⍰⍭⍸]$/)) {
            tokens.push({ token: word, type: 'glyph' });
          } else if (word.match(/^\d+$/)) {
            tokens.push({ token: word, type: 'number' });
          } else if (word.match(/^[a-zA-Z_][a-zA-Z0-9_]*$/)) {
            tokens.push({ token: word, type: 'identifier' });
          } else if (word.match(/^".*"$/)) {
            tokens.push({ token: word, type: 'string' });
          } else {
            // Character-level tokenization for unknown
            for (const char of word) {
              tokens.push({ token: char, type: 'char' });
            }
          }
        }

        return tokens;
      },

      encode: function(text) {
        const tokens = this.tokenize(text);
        // Simulate token IDs (in reality, would use vocab mapping)
        return tokens.map((t, i) => 1000 + i % 1000);
      }
    };
  }

  async loadGGLTokenizer() {
    // Simulate loading embedded GGL tokenizer
    return {
      name: 'GGL Tokenizer',
      vocabSize: 32000,
      glyphs: {
        circle: '◯',
        square: '□',
        triangle: '△',
        union: '⍯',
        intersection: '⍰',
        difference: '⍭',
        array: '⍸',
        at: '@',
        pipe: '|'
      },
      operators: {
        encrypt: 'encrypt',
        decrypt: 'decrypt',
        rotate: 'rotate',
        mirror: 'mirror',
        spherical_grid: 'spherical_grid',
        generate_path: 'generate_path',
        apply_weights: 'apply_weights'
      },

      tokenize: function(expression) {
        const tokens = [];
        let current = '';

        for (let i = 0; i < expression.length; i++) {
          const char = expression[i];

          // Check for glyphs
          if (Object.values(this.glyphs).includes(char)) {
            if (current) {
              tokens.push({ token: current, type: 'text' });
              current = '';
            }
            tokens.push({ token: char, type: 'glyph' });
          }
          // Check for whitespace
          else if (char.match(/\s/)) {
            if (current) {
              tokens.push({ token: current, type: 'text' });
              current = '';
            }
          }
          // Check for operators
          else if (char.match(/[a-zA-Z]/)) {
            current += char;
            // Check if current forms an operator
            if (this.operators[current]) {
              tokens.push({ token: current, type: 'operator' });
              current = '';
            }
          }
          // Check for special characters
          else if (char.match(/[{}()\[\]@|]/)) {
            if (current) {
              tokens.push({ token: current, type: 'text' });
              current = '';
            }
            tokens.push({ token: char, type: 'special' });
          }
          else {
            current += char;
          }
        }

        if (current) {
          tokens.push({ token: current, type: 'text' });
        }

        return tokens;
      },

      encode: function(expression) {
        const tokens = this.tokenize(expression);
        // Simulate token IDs
        return tokens.map((t, i) => 2000 + i % 1000);
      }
    };
  }

  // ===========================================
  // NEURAL MODEL (SIMPLIFIED FOR SVG)
  // ===========================================

  class NeuralBridgeModel {
    constructor() {
      // Simulated neural network parameters
      this.layers = 32;
      this.embeddingDim = 4096;
      this.heads = 32;
      this.parameters = 7_000_000_000; // 7B

      // Simulated weights (in reality, would load from embedded data)
      this.weights = {
        embedding: this.createRandomMatrix(50257, 4096),
        attention: Array(32).fill().map(() => ({
          query: this.createRandomMatrix(4096, 4096),
          key: this.createRandomMatrix(4096, 4096),
          value: this.createRandomMatrix(4096, 4096),
          output: this.createRandomMatrix(4096, 4096)
        })),
        feedforward: Array(32).fill().map(() => ({
          up: this.createRandomMatrix(4096, 16384),
          gate: this.createRandomMatrix(4096, 16384),
          down: this.createRandomMatrix(16384, 4096)
        })),
        output: this.createRandomMatrix(4096, 32000)
      };
    }

    createRandomMatrix(rows, cols) {
      // Create simulated weight matrix
      return {
        rows,
        cols,
        data: Array(rows * cols).fill().map(() => Math.random() * 2 - 1)
      };
    }

    async forward(tokens, sourceLang, targetLang) {
      // Simulated forward pass
      const startTime = performance.now();

      // Embed tokens
      let hidden = this.embed(tokens);

      // Apply attention layers
      const attentionWeights = [];
      for (let i = 0; i < this.layers; i++) {
        const result = this.attentionLayer(hidden, i);
        hidden = result.hidden;
        attentionWeights.push(result.attention);
      }

      // Generate output logits
      const logits = this.outputLayer(hidden);

      // Convert to target tokens
      const outputTokens = this.sampleFromLogits(logits, targetLang);

      const inferenceTime = performance.now() - startTime;

      return {
        tokens: outputTokens,
        attentionWeights,
        hiddenStates: hidden,
        performance: { inferenceTime }
      };
    }

    embed(tokens) {
      // Simulated embedding lookup
      return tokens.map(() => 
        Array(this.embeddingDim).fill().map(() => Math.random() * 2 - 1)
      );
    }

    attentionLayer(hidden, layerIndex) {
      // Simulated attention
      const sequenceLength = hidden.length;
      const attention = [];

      // Create attention matrix
      for (let i = 0; i < sequenceLength; i++) {
        attention[i] = [];
        for (let j = 0; j < sequenceLength; j++) {
          // Simulated attention scores
          attention[i][j] = Math.random();
        }
      }

      // Apply softmax
      for (let i = 0; i < sequenceLength; i++) {
        const row = attention[i];
        const max = Math.max(...row);
        const exp = row.map(x => Math.exp(x - max));
        const sum = exp.reduce((a, b) => a + b, 0);
        attention[i] = exp.map(x => x / sum);
      }

      // Update hidden states (simplified)
      const newHidden = hidden.map((vec, i) => 
        vec.map((x, j) => x * (1 + Math.random() * 0.1))
      );

      return { hidden: newHidden, attention };
    }

    outputLayer(hidden) {
      // Simulated output projection
      const vocabSize = 32000;
      return hidden.map(() => 
        Array(vocabSize).fill().map(() => Math.random() * 2 - 1)
      );
    }

    sampleFromLogits(logits, targetLang) {
      // Simple sampling (in reality would use beam search)
      const tokens = [];
      for (const tokenLogits of logits) {
        // Softmax
        const max = Math.max(...tokenLogits);
        const exp = tokenLogits.map(x => Math.exp(x - max));
        const sum = exp.reduce((a, b) => a + b, 0);
        const probs = exp.map(x => x / sum);

        // Sample
        let random = Math.random();
        let chosenIndex = 0;
        for (let i = 0; i < probs.length; i++) {
          random -= probs[i];
          if (random <= 0) {
            chosenIndex = i;
            break;
          }
        }

        // Convert to token based on target language
        let token;
        if (targetLang === 'GGL') {
          token = this.indexToGGLToken(chosenIndex);
        } else {
          token = this.indexToSVG3DToken(chosenIndex);
        }

        tokens.push(token);
      }

      return tokens;
    }

    indexToGGLToken(index) {
      const glyphs = ['◯', '□', '△', '⍯', '⍰', '⍭', '⍸', '@', '|'];
      const operators = ['encrypt', 'decrypt', 'rotate', 'mirror', 'spherical_grid', 'generate_path', 'apply_weights'];

      if (index < glyphs.length) return glyphs[index];
      if (index < glyphs.length + operators.length) return operators[index - glyphs.length];
      return `token_${index}`;
    }

    indexToSVG3DToken(index) {
      const operators = ['⤍', '↻', '⟲', '⟿', '⤎', '↔', '⤦', '⤂'];
      if (index < operators.length) return operators[index];
      return `token_${index}`;
    }
  }

  // ===========================================
  // NEURAL TRANSLATION ENGINE
  // ===========================================

  async neuralTranslateSVG3DtoGGL(svg3dCommand) {
    const startTime = performance.now();

    try {
      // Tokenize SVG-3D
      const tokenizationStart = performance.now();
      const svg3dTokens = this.svg3dTokenizer.encode(svg3dCommand);
      this.bridgeState.performance.tokenizationTime = performance.now() - tokenizationStart;

      // Display tokens
      this.displaySVG3DTokens(svg3dCommand, svg3dTokens);

      // Neural inference
      const inferenceStart = performance.now();
      const result = await this.neuralModel.forward(
        svg3dTokens, 
        'SVG-3D', 
        'GGL'
      );
      this.bridgeState.performance.inferenceTime = performance.now() - inferenceStart;

      // Store attention weights for visualization
      this.bridgeState.attentionWeights = result.attentionWeights;

      // Convert output tokens to GGL expression
      const gglExpression = result.tokens.join(' ').replace(/\s+/g, ' ').trim();

      // Create translation record
      const translation = {
        id: `neural_${Date.now()}`,
        timestamp: Date.now(),
        source: {
          language: 'SVG-3D',
          command: svg3dCommand,
          tokens: svg3dTokens,
          tokenCount: svg3dTokens.length
        },
        target: {
          language: 'GGL',
          expression: gglExpression,
          tokens: result.tokens,
          tokenCount: result.tokens.length
        },
        neural: {
          attention: result.attentionWeights,
          hiddenStates: result.hiddenStates,
          confidence: this.calculateConfidence(result)
        },
        performance: {
          totalTime: performance.now() - startTime,
          tokenizationTime: this.bridgeState.performance.tokenizationTime,
          inferenceTime: this.bridgeState.performance.inferenceTime
        }
      };

      // Store translation
      this.bridgeState.translations.push(translation);

      // Update visualizations
      this.updateWeightVisualization();
      this.updateAttentionVisualization(result.attentionWeights[0]);

      // Update UI
      this.updateGGLExpression(gglExpression);
      this.updateModelStats();
      this.logNeural(`Neural translation: ${svg3dCommand} → ${gglExpression}`);

      return translation;

    } catch (error) {
      this.logNeural(`Neural translation error: ${error.message}`, 'error');
      throw error;
    }
  }

  async neuralTranslateGGLtoSVG3D(gglExpression) {
    const startTime = performance.now();

    try {
      // Tokenize GGL
      const tokenizationStart = performance.now();
      const gglTokens = this.gglTokenizer.encode(gglExpression);
      this.bridgeState.performance.tokenizationTime = performance.now() - tokenizationStart;

      // Display tokens
      this.displayGGLTokens(gglExpression, gglTokens);

      // Neural inference
      const inferenceStart = performance.now();
      const result = await this.neuralModel.forward(
        gglTokens,
        'GGL',
        'SVG-3D'
      );
      this.bridgeState.performance.inferenceTime = performance.now() - inferenceStart;

      // Store attention weights
      this.bridgeState.attentionWeights = result.attentionWeights;

      // Convert output tokens to SVG-3D command
      const svg3dCommand = result.tokens.join(' ');

      // Create translation record
      const translation = {
        id: `neural_${Date.now()}`,
        timestamp: Date.now(),
        source: {
          language: 'GGL',
          expression: gglExpression,
          tokens: gglTokens,
          tokenCount: gglTokens.length
        },
        target: {
          language: 'SVG-3D',
          command: svg3dCommand,
          tokens: result.tokens,
          tokenCount: result.tokens.length
        },
        neural: {
          attention: result.attentionWeights,
          hiddenStates: result.hiddenStates,
          confidence: this.calculateConfidence(result)
        },
        performance: {
          totalTime: performance.now() - startTime,
          tokenizationTime: this.bridgeState.performance.tokenizationTime,
          inferenceTime: this.bridgeState.performance.inferenceTime
        }
      };

      // Store translation
      this.bridgeState.translations.push(translation);

      // Update visualizations
      this.updateWeightVisualization();
      this.updateAttentionVisualization(result.attentionWeights[0]);

      // Update UI
      this.updateSVG3DCommand(svg3dCommand);
      this.updateModelStats();
      this.logNeural(`Neural translation: ${gglExpression} → ${svg3dCommand}`);

      return translation;

    } catch (error) {
      this.logNeural(`Neural translation error: ${error.message}`, 'error');
      throw error;
    }
  }

  calculateConfidence(result) {
    // Calculate confidence score from neural output
    // Simplified: average of attention weights
    if (!result.attentionWeights || result.attentionWeights.length === 0) {
      return 0.5;
    }

    const firstAttention = result.attentionWeights[0];
    let sum = 0;
    let count = 0;

    for (const row of firstAttention) {
      for (const val of row) {
        sum += val;
        count++;
      }
    }

    return count > 0 ? (sum / count) * 100 : 50;
  }

  // ===========================================
  // VISUALIZATION
  // ===========================================

  initWeightVisualization() {
    const canvas = document.getElementById('weight-canvas');
    if (!canvas) return;

    this.weightCanvas = canvas;
    this.weightCtx = canvas.getContext('2d');

    // Set canvas dimensions
    canvas.width = 230;
    canvas.height = 50;
  }

  initAttentionVisualization() {
    const canvas = document.getElementById('attention-canvas');
    if (!canvas) return;

    this.attentionCanvas = canvas;
    this.attentionCtx = canvas.getContext('2d');

    // Set canvas dimensions
    canvas.width = 230;
    canvas.height = 50;
  }

  updateWeightVisualization() {
    if (!this.weightCtx) return;

    const ctx = this.weightCtx;
    const width = this.weightCanvas.width;
    const height = this.weightCanvas.height;

    // Clear canvas
    ctx.fillStyle = 'rgba(0,0,0,0.3)';
    ctx.fillRect(0, 0, width, height);

    // Draw weight matrix visualization
    const cellSize = 3;
    const padding = 2;

    for (let i = 0; i < 20; i++) {
      for (let j = 0; j < 10; j++) {
        const x = padding + i * (cellSize + 1);
        const y = padding + j * (cellSize + 1);

        // Random weight value for visualization
        const weight = Math.random();

        // Map weight to color
        let color;
        if (weight > 0) {
          const intensity = Math.floor(weight * 255);
          color = `rgb(${intensity}, ${intensity}, 255)`;
        } else {
          const intensity = Math.floor(-weight * 255);
          color = `rgb(255, ${intensity}, ${intensity})`;
        }

        ctx.fillStyle = color;
        ctx.fillRect(x, y, cellSize, cellSize);
      }
    }
  }

  updateAttentionVisualization(attentionMatrix) {
    if (!this.attentionCtx || !attentionMatrix) return;

    const ctx = this.attentionCtx;
    const width = this.attentionCanvas.width;
    const height = this.attentionCanvas.height;

    // Clear canvas
    ctx.fillStyle = 'rgba(0,0,0,0.3)';
    ctx.fillRect(0, 0, width, height);

    // Draw attention heatmap
    const size = Math.min(attentionMatrix.length, 10);
    const cellSize = Math.min(width / size, height / size) - 2;

    for (let i = 0; i < size; i++) {
      for (let j = 0; j < size; j++) {
        const x = 2 + j * (cellSize + 2);
        const y = 2 + i * (cellSize + 2);

        // Get attention value (clamped to matrix size)
        const attention = attentionMatrix[i]?.[j] || 0;

        // Map to color (heatmap: blue -> green -> yellow -> red)
        let r, g, b;
        if (attention < 0.25) {
          // Blue to green
          const t = attention * 4;
          r = 0;
          g = Math.floor(t * 255);
          b = Math.floor((1 - t) * 255);
        } else if (attention < 0.5) {
          // Green to yellow
          const t = (attention - 0.25) * 4;
          r = Math.floor(t * 255);
          g = 255;
          b = 0;
        } else if (attention < 0.75) {
          // Yellow to orange
          const t = (attention - 0.5) * 4;
          r = 255;
          g = Math.floor((1 - t) * 255);
          b = 0;
        } else {
          // Orange to red
          const t = (attention - 0.75) * 4;
          r = 255;
          g = Math.floor((1 - t) * 128);
          b = 0;
        }

        ctx.fillStyle = `rgb(${r}, ${g}, ${b})`;
        ctx.fillRect(x, y, cellSize, cellSize);

        // Draw attention value text for high values
        if (attention > 0.7) {
          ctx.fillStyle = '#ffffff';
          ctx.font = '6px monospace';
          ctx.textAlign = 'center';
          ctx.textBaseline = 'middle';
          ctx.fillText(
            attention.toFixed(2),
            x + cellSize / 2,
            y + cellSize / 2
          );
        }
      }
    }
  }

  // ===========================================
  // TOKEN DISPLAY
  // ===========================================

  displaySVG3DTokens(command, tokenIds) {
    const tokensDiv = document.getElementById('svg3d-tokens');
    if (tokensDiv) {
      // Tokenize the command for display
      const tokens = this.svg3dTokenizer.tokenize(command);
      const display = tokens.map((t, i) => 
        `<span style="color: ${this.getTokenColor(t.type)}">${t.token}</span>:${tokenIds[i] || '?'}`
      ).join(' ');

      tokensDiv.innerHTML = display;
    }
  }

  displayGGLTokens(expression, tokenIds) {
    const tokensDiv = document.getElementById('ggl-tokens');
    if (tokensDiv) {
      // Tokenize the expression for display
      const tokens = this.gglTokenizer.tokenize(expression);
      const display = tokens.map((t, i) => 
        `<span style="color: ${this.getTokenColor(t.type)}">${t.token}</span>:${tokenIds[i] || '?'}`
      ).join(' ');

      tokensDiv.innerHTML = display;
    }
  }

  getTokenColor(type) {
    const colors = {
      operator: '#16f2aa',
      glyph: '#ff3366',
      number: '#9966ff',
      identifier: '#00e0ff',
      string: '#ffaa00',
      special: '#ff00ff',
      char: '#cccccc',
      text: '#ffffff'
    };
    return colors[type] || '#ffffff';
  }

  // ===========================================
  // UI UPDATES
  // ===========================================

  updateBridgeStatus(message) {
    const status = document.getElementById('bridge-status');
    if (status) status.textContent = `Neural Bridge: ${message}`;
  }

  updateGGLExpression(expression) {
    const editor = document.getElementById('ggl-editor');
    if (editor) editor.value = expression;
  }

  updateSVG3DCommand(command) {
    const input = document.getElementById('svg3d-input');
    if (input) input.value = command;
  }

  updateModelStats() {
    // Update model statistics display
    const stats = {
      layers: document.getElementById('model-layers'),
      params: document.getElementById('model-params'),
      memory: document.getElementById('model-memory'),
      precision: document.getElementById('model-precision'),
      throughput: document.getElementById('model-throughput'),
      latency: document.getElementById('model-latency'),
      accuracy: document.getElementById('model-accuracy'),
      loss: document.getElementById('model-loss')
    };

    if (stats.layers) stats.layers.textContent = `Layers: ${this.neuralModel.layers}`;
    if (stats.params) stats.params.textContent = `Params: ${(this.neuralModel.parameters / 1e9).toFixed(1)}B`;
    if (stats.memory) stats.memory.textContent = `Memory: 1.84GB`;
    if (stats.precision) stats.precision.textContent = `Precision: float16`;

    // Calculate performance stats
    const tokenizationTime = this.bridgeState.performance.tokenizationTime;
    const inferenceTime = this.bridgeState.performance.inferenceTime;

    if (stats.throughput && inferenceTime > 0) {
      const tokensPerSecond = 1000 / inferenceTime;
      stats.throughput.textContent = `Throughput: ${tokensPerSecond.toFixed(1)} tokens/s`;
    }

    if (stats.latency) {
      stats.latency.textContent = `Latency: ${inferenceTime.toFixed(1)}ms`;
    }

    if (stats.accuracy) {
      // Simplified accuracy calculation
      const lastTranslation = this.bridgeState.translations[this.bridgeState.translations.length - 1];
      const accuracy = lastTranslation?.neural?.confidence || 0;
      stats.accuracy.textContent = `Accuracy: ${accuracy.toFixed(1)}%`;
    }

    if (stats.loss) {
      // Simplified loss calculation
      const loss = 1 - (this.bridgeState.performance.inferenceTime / 100);
      stats.loss.textContent = `Loss: ${loss.toFixed(4)}`;
    }
  }

  logNeural(message, type = 'info') {
    const output = document.getElementById('neural-output');
    if (!output) return;

    const timestamp = new Date().toLocaleTimeString();
    const color = type === 'error' ? '#ff3366' : 
                 type === 'warning' ? '#ffaa00' : '#ffaa00';

    const entry = document.createElement('div');
    entry.style.color = color;
    entry.style.margin = '2px 0';
    entry.style.fontSize = '8px';
    entry.textContent = `[${timestamp}] ${message}`;

    output.appendChild(entry);
    output.scrollTop = output.scrollHeight;

    // Trim if too many entries
    if (output.children.length > 15) {
      output.removeChild(output.firstChild);
    }
  }
}

// ===========================================
// GLOBAL INITIALIZATION
// ===========================================

let neuralBridge;

function initNeuralBridge() {
  try {
    neuralBridge = new NeuralKuhulBridge();
    window.neuralBridge = neuralBridge;

    console.log('🧠 Neural K\'UHUL SVG-3D ↔ GGL Bridge initialized');

    // Initial visualizations
    neuralBridge.updateWeightVisualization();

  } catch (error) {
    console.error('Failed to initialize neural bridge:', error);
  }
}

// ===========================================
// UI EVENT HANDLERS
// ===========================================

function neuralTranslate() {
  const svg3dInput = document.getElementById('svg3d-input');
  const gglEditor = document.getElementById('ggl-editor');

  if (svg3dInput && svg3dInput.value && neuralBridge) {
    // Translate SVG-3D to GGL
    neuralBridge.neuralTranslateSVG3DtoGGL(svg3dInput.value);
  } else if (gglEditor && gglEditor.value && neuralBridge) {
    // Translate GGL to SVG-3D
    neuralBridge.neuralTranslateGGLtoSVG3D(gglEditor.value);
  }
}

function optimizeWeights() {
  if (!neuralBridge) return;

  neuralBridge.logNeural('Optimizing model weights...', 'info');

  // Simulate weight optimization
  setTimeout(() => {
    neuralBridge.updateWeightVisualization();
    neuralBridge.logNeural('Weights optimized using gradient descent', 'info');
    neuralBridge.updateBridgeStatus('Weights Optimized');
  }, 1000);
}

function highlightGGLTokens(expression) {
  // Update token display as user types
  if (neuralBridge && neuralBridge.gglTokenizer) {
    const tokenIds = neuralBridge.gglTokenizer.encode(expression);
    neuralBridge.displayGGLTokens(expression, tokenIds);
  }
}

function addGlyph(glyph) {
  const editor = document.getElementById('ggl-editor');
  if (editor) {
    editor.value += glyph;
    highlightGGLTokens(editor.value);
  }
}

function loadExample(type) {
  const examples = {
    encrypt: '(⤍) vector path="M0,0 C10,5 20,-5 30,0"',
    compress: '(↻) geometry angle=45',
    sphere: '(⟲) 1 360',
    neural: '(⟿) "generate pattern" seed=123'
  };

  const input = document.getElementById('svg3d-input');
  if (input && examples[type]) {
    input.value = examples[type];
  }
}

function loadGGLExample(type) {
  const examples = {
    gear: '◯ {r:10} ⍰ [ ◯ {r:8} ⍰ ( □ {s:2} ⍸ 20 ) ]',
    web: '[ ◯ {r: r} | r in [1,2,3,4,5] ]',
    lattice: '[ □ {s:1} at (x, y, z) | x in 0..2, y in 0..2, z in 0..2 ]'
  };

  const editor = document.getElementById('ggl-editor');
  if (editor && examples[type]) {
    editor.value = examples[type];
    highlightGGLTokens(editor.value);
  }
}

// Initialize when ready
if (document.readyState === 'loading') {
  document.addEventListener('DOMContentLoaded', initNeuralBridge);
} else {
  initNeuralBridge();
}

// Global Neural API
window.NeuralBridgeAPI = {
  translateSVG3DtoGGL: (cmd) => neuralBridge?.neuralTranslateSVG3DtoGGL(cmd),
  translateGGLtoSVG3D: (expr) => neuralBridge?.neuralTranslateGGLtoSVG3D(expr),
  getWeights: () => neuralBridge?.neuralModel.weights,
  getAttention: () => neuralBridge?.bridgeState.attentionWeights
};

// SCXQ2 projection-only API
if (typeof runInferenceFromSCXQ2 === 'function') {
  window.ASXInferenceBridge = {
    runFromSCXQ2: (args) => runInferenceFromSCXQ2({ ...args, bridge: window.NeuralBridgeAPI })
  };
}
